INSERT INTO public.state_law_provisions
  (act_id, state_code, topic, rule_kind, threshold_numeric, threshold_unit, summary, statute_citation, source_url, source_date, effective_year)
SELECT a.id, 'WI', v.topic, v.rule_kind, v.threshold_numeric, v.threshold_unit, v.summary, v.citation, v.url, DATE '2026-06-11', 2026
FROM public.state_landlord_tenant_acts a CROSS JOIN (VALUES
  ('entry_notice_hours', 'min', 12::numeric, 'hours', 'At least 12 hours'' advance notice is generally required before the landlord enters.', 'Wis. Admin. Code § ATCP 134.09(2)(a)2.', 'https://docs.legis.wisconsin.gov/code/admin_code/atcp/090/134/09/2'),
  ('deposit_return_days', 'max', 21::numeric, 'days', 'The deposit must be returned within 21 days after the tenancy ends.', 'Wis. Admin. Code § ATCP 134.06(2); Wis. Stat. § 704.28(4)', 'https://docs.legis.wisconsin.gov/code/admin_code/atcp/090/134/06/2'),
  ('notice_to_vacate_days', 'min', 28::numeric, 'days', 'Ending a month-to-month tenancy generally requires at least 28 days'' notice.', 'Wis. Stat. § 704.19(3)', 'https://docs.legis.wisconsin.gov/statutes/statutes/704/19')
) AS v(topic, rule_kind, threshold_numeric, threshold_unit, summary, citation, url)
WHERE a.state_code = 'WI' AND a.act_key = 'residential' AND a.effective_year = 2026;

